module RefModule(datain, dataout, clk, clr, WE);input [31:0] datain;
    output [31:0] dataout;
    input clk, clr, WE;

    reg [31:0] unused_register;

always @(posedge clk or posedge clr)
begin
  if(clr)
    unused_register = 0;  
  else
    if(WE == 1)
    unused_register =  datain;
end    
  assign dataout = unused_register;

endmodule
